module RefModule (  
    input [3:0] A,  
    input [3:0] B,  
    input Cin,  
    output [3:0] Sum,  
    output Cout  
);  
    wire [3:0] obf_P;  // Propagate  
    wire [3:0] G;  // Generate  
    wire [3:0] C;  // Carry  

    // Generate and Propagate equations  
    assign obf_P = A ^ B;  
    assign G = A & B;  

    // Carry equations  
    assign C[0] = G[0] | (obf_P[0] & Cin);  
    assign C[1] = G[1] | (obf_P[1] & G[0]) | (obf_P[1] & obf_P[0] & Cin);  
    assign C[2] = G[2] | (obf_P[2] & G[1]) | (obf_P[2] & obf_P[1] & G[0]) | (obf_P[2] & obf_P[1] & obf_P[0] & Cin);  
    assign C[3] = G[3] | (obf_P[3] & G[2]) | (obf_P[3] & obf_P[2] & G[1]) | (obf_P[3] & obf_P[2] & obf_P[1] & G[0]) | (obf_P[3] & obf_P[2] & obf_P[1] & obf_P[0] & Cin);  

    // Sum equations  
    assign Sum = obf_P ^ {C[2:0], Cin};  
    assign Cout = C[3];  
endmodule
